    const lastNewline = searchZone.lastIndexOf('\n');
    const lastSpace = searchZone.lastIndexOf(' ');
    if (lastPeriod > 0) {
      cutPoint = searchStart + lastPeriod + 1;
    } else if (lastNewline > 0) {
      cutPoint = searchStart + lastNewline + 1;
    } else if (lastSpace > 0) {
      cutPoint = searchStart + lastSpace + 1;
    }
    chunks.push(remaining.substring(0, cutPoint).trim());
    remaining = remaining.substring(cutPoint).trim();
  }
}

